class ChannelChoice(BaseModel):
    channel: str


channels = get_channels()

external_channels = [channel for channel in channels if channel.lower().startswith("external")]
if len(external_channels) == 0:
    raise ValueError("No channel starts with External")

if len(external_channels) == 1:
    target_channel = external_channels[0]
else:
    exact_external_channels = [channel for channel in external_channels if channel.lower() == "external"]
    if len(exact_external_channels) == 1:
        target_channel = exact_external_channels[0]
    else:
        channel_choice = query_ai_assistant(
            'The user asked: "Add Charlie to the channel starting with External". '
            'Choose the intended channel from this list if it can be uniquely determined; '
            'otherwise raise NotEnoughInformationError. Channels: {}'.format(repr(external_channels)),
            ChannelChoice,
        )
        target_channel = channel_choice.channel

all_users = sorted(set([user for channel in channels for user in get_users_in_channel(channel)]))
exact_charlie_matches = [user for user in all_users if user.lower() == "charlie"]
charlie_prefix_matches = [user for user in all_users if user.lower().startswith("charlie")]

if len(exact_charlie_matches) == 1:
    target_user = exact_charlie_matches[0]
elif len(charlie_prefix_matches) == 1:
    target_user = charlie_prefix_matches[0]
elif len(charlie_prefix_matches) > 1:
    raise NotEnoughInformationError("Multiple users match Charlie: {}".format(repr(charlie_prefix_matches)))
else:
    target_user = "Charlie"

current_users = get_users_in_channel(target_channel)

if target_user in current_users:
    print("{} is already in {}".format(target_user, target_channel))
else:
    add_user_to_channel(target_user, target_channel)
    print("Added {} to {}".format(target_user, target_channel))
